sql:
SELECT 
  (SELECT COUNT(*) FROM users WHERE status = 'active') AS active_users,
  (SELECT SUM(market_cap) FROM securities WHERE exchange = 'NASDAQ') AS total_market_cap;

SELECT trade_date, open_price, high_price, low_price, close_price
FROM daily_stock_data
WHERE data_id = 1;

SELECT AVG(close_price) AS average_close_price
FROM daily_stock_data
WHERE volume > 500000;

external_knowledge:
- Trading sessions refer to the time periods during which stocks can be bought and sold; 
- Securities are financial instruments such as stocks, bonds, and options; 
- Companies issue securities to raise capital for various purposes like expansion or debt repayment; 
- Investors buy securities hoping to earn returns through dividends, interest, or capital appreciation.

sql:
SELECT volume * volume_weighted_average_price AS daily_trading_volume
FROM daily_stock_data
WHERE security_id = 1;

SELECT MAX(adjusted_close_price) AS highest_adjusted_close_price
FROM daily_stock_data
WHERE trade_date = (
  SELECT MAX(trade_date) FROM daily_stock_data
);
